// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
// STRY0076609 removed the condition to stop when loading.  Even set when loading
if(newValue == 'true'){	
		if(g_scratchpad.calchaschildren <= 0)
		g_form.showFieldMsg('u_wait_for_subtasks_to_finish', getMessage('Tasker - Wait State Warning Message'), 'error', false);

	var msg = getMessage('Tasker - Wait State Information Message');

		// call back to server to see if this task and the child task are both approval types
	var ajax  = new GlideAjax('ClientTaskTemplateHelpers');
	ajax.addParam('sysparm_name', 'checkForApprovalTypeOnTaskTempAndSubTaskTemp');
	ajax.addParam('taskTempId', g_scratchpad.parent_task_def);
	ajax.getXML(function(response){
		try{
			var data = response.responseXML.documentElement.getAttribute("answer");
			if(data == 'true'){
				msg = msg + getMessage('Tasker - Wait State - Information - Approval type with Approval Subtask');
			}
			g_form.showFieldMsg('u_wait_for_subtasks_to_finish', msg,'info');
		}catch(e){
			jslog (e);
		}
	});

} else if (!isLoading && newValue == 'false'){
	g_form.showFieldMsg('u_wait_for_subtasks_to_finish', getMessage('Tasker - Wait State Information - Task is no longer dependent on the completion of its Subtasks'),'info');
}

}
